content.text:
Here's what ForgeScript experiment code looks like - clean, declarative, and leveraging TypeScript's full power:

## Basic Stroop Task Example

```typescript
import { Experiment, Timeline, Trial, Stimulus, Response } from '@psyforge/api';

// Define the classic Stroop task with modern TypeScript
const stroopTask = new Experiment({ 
  name: 'Stroop Color-Word Interference',
  version: '1.0.0',
  description: 'Classic Stroop task measuring color-word interference effects'
})
  .addTimeline(
    new Timeline({ id: 'practice' })
      .addTrial(
        new Trial({ id: 'practice_congruent' })
          .addStimulus(new Stimulus.FixationCross({
            duration: 500,
            size: { width: 40, height: 40 },
            color: '#000000'
          }))
          .addStimulus(new Stimulus.Text({
            content: 'RED',
            color: 'red',          // Congruent condition
            fontSize: 48,
            fontFamily: 'Arial',
            timing: { onset: 500, duration: 1500 },
            position: { x: 0, y: 0 }
          }))
          .addResponse(new Response.KeyPress({
            keys: ['r', 'g', 'b', 'y'],
            correctKey: 'r',
            timeout: 2000,
            prompt: 'Press R=Red, G=Green, B=Blue, Y=Yellow'
          }))
      )
      .addTrial(
        new Trial({ id: 'practice_incongruent' })
          .addStimulus(new Stimulus.FixationCross({ duration: 500 }))
          .addStimulus(new Stimulus.Text({
            content: 'RED',
            color: 'blue',         // Incongruent condition
            fontSize: 48,
            timing: { onset: 500, duration: 1500 }
          }))
          .addResponse(new Response.KeyPress({
            keys: ['r', 'g', 'b', 'y'],
            correctKey: 'r',       // Correct based on word, not color
            timeout: 2000
          }))
      )
      .setRandomization({ method: 'shuffle' })
      .repeat(5) // 5 practice trials
  )
  .addTimeline(
    new Timeline({ id: 'main_experiment' })
      .addTrials(createStroopTrials()) // Generate full trial set
      .setRandomization({ 
        method: 'latinSquare',
        counterbalance: ['color', 'word', 'congruency']
      })
  )
  .setRecruitment({
    providers: ['prolific'],
    criteria: {
      age: { min: 18, max: 65 },
      language: 'english_native',
      excludePrevious: true
    },
    compensation: { base: 8.50, currency: 'USD' },
    target: { n: 120 }
  })
  .requirePower({ 
    effect: 0.5,      // Medium effect size expected
    alpha: 0.05, 
    target: 0.8       // 80% power required
  })
  .validate()         // Compile-time validation
  .compile();         // Generate executable experiment

// Helper function for generating trial combinations
function createStroopTrials(): Trial[] {
  const colors = ['red', 'green', 'blue', 'yellow'];
  const words = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
  const trials: Trial[] = [];

  // Generate all combinations
  for (const wordIndex in words) {
    for (const colorIndex in colors) {
      const word = words[wordIndex];
      const color = colors[colorIndex];
      const isCongruent = wordIndex === colorIndex;
      const correctKey = ['r', 'g', 'b', 'y'][wordIndex];

      trials.push(
        new Trial({ 
          id: `${word.toLowerCase()}_${color}_${isCongruent ? 'congruent' : 'incongruent'}`,
          metadata: { 
            condition: isCongruent ? 'congruent' : 'incongruent',
            word: word,
            color: color 
          }
        })
          .addStimulus(new Stimulus.FixationCross({ duration: 500 }))
          .addStimulus(new Stimulus.Text({
            content: word,
            color: color,
            fontSize: 48,
            timing: { onset: 500, duration: 1500 }
          }))
          .addResponse(new Response.KeyPress({
            keys: ['r', 'g', 'b', 'y'],
            correctKey: correctKey,
            timeout: 2000
          }))
      );
    }
  }

  return trials;
}
```

## Advanced Example: N-Back Working Memory Task

```typescript
import { Experiment, Timeline, Trial, Variable, Conditional } from '@psyforge/api';

const nBackTask = new Experiment({ name: '2-Back Working Memory Task' })
  // Define experiment variables
  .defineVariable('nBackLevel', 2)
  .defineVariable('targetProbability', 0.3)

  .addTimeline(
    new Timeline({ id: 'instructions' })
      .addTrial(
        new Trial()
          .addStimulus(new Stimulus.Text({
            content: `
              You will see letters appearing one at a time.
              Press SPACE when the current letter matches 
              the letter from ${Variable.get('nBackLevel')} positions back.
            `,
            fontSize: 24,
            maxWidth: 600,
            wordWrap: true
          }))
          .addResponse(new Response.KeyPress({ 
            keys: ['space'], 
            prompt: 'Press SPACE to continue' 
          }))
      )
  )

  .addTimeline(
    new Timeline({ id: 'nback_trials' })
      .addTrials(generateNBackSequence({
        sequenceLength: 100,
        nBack: Variable.get('nBackLevel'),
        targetRate: Variable.get('targetProbability'),
        stimulusSet: ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']
      }))
      .onTrialComplete((trial, data) => {
        // Real-time performance monitoring
        updatePerformanceMetrics(data);
      })
  )

  // Conditional timeline based on performance
  .addTimeline(
    new Conditional({
      condition: () => getAccuracy() < 0.6,
      ifTrue: new Timeline({ id: 'additional_practice' })
        .addTrial(createFeedbackTrial('Let\'s try some more practice trials'))
        .addTrials(generateNBackSequence({ sequenceLength: 20, nBack: 1 })),
      ifFalse: new Timeline({ id: 'completion' })
        .addTrial(createFeedbackTrial('Great job! Task complete.'))
    })
  )

  .requirePower({ effect: 0.7, alpha: 0.05, target: 0.9 })
  .compile();

// Advanced stimulus generation
function generateNBackSequence(config: NBackConfig): Trial[] {
  const sequence = generateBalancedSequence(config);

  return sequence.map((stimulus, index) => {
    const isTarget = index >= config.nBack && 
                    sequence[index - config.nBack] === stimulus;

    return new Trial({ 
      id: `nback_${index}`,
      metadata: { 
        position: index,
        stimulus: stimulus,
        isTarget: isTarget,
        correctResponse: isTarget ? 'space' : null
      }
    })
      .addStimulus(new Stimulus.Text({
        content: stimulus,
        fontSize: 72,
        color: '#000000',
        timing: { onset: 0, duration: 500 }
      }))
      .addStimulus(new Stimulus.Blank({
        timing: { onset: 500, duration: 1500 } // ISI
      }))
      .addResponse(new Response.KeyPress({
        keys: ['space'],
        timeout: 2000,
        allowEarlyResponse: true,
        correctKey: isTarget ? 'space' : null
      }));
  });
}
```

## Complex Multi-Modal Example: EEG + Eye-Tracking

```typescript
import { Experiment, Device, Trigger } from '@psyforge/api';

const multimodeTask = new Experiment({ name: 'Attention Networks EEG Study' })
  // Connect to lab equipment
  .addDevice(new Device.EEG({
    type: 'biosemi',
    channels: 64,
    samplingRate: 1024
  }))
  .addDevice(new Device.EyeTracker({
    type: 'eyelink1000',
    samplingRate: 500,
    calibrationPoints: 9
  }))

  .addTimeline(
    new Timeline({ id: 'calibration' })
      .addTrial(
        new Trial()
          .addProcedure(new Procedure.EyeTrackerCalibration())
          .addProcedure(new Procedure.EEGImpedanceCheck({ 
            maxImpedance: 5000 
          }))
      )
  )

  .addTimeline(
    new Timeline({ id: 'main_task' })
      .addTrial(
        new Trial({ id: 'attention_trial' })
          // Trigger EEG recording
          .addTrigger(new Trigger.EEG({ 
            code: 100, 
            timing: 'stimulus_onset' 
          }))

          // Present central fixation
          .addStimulus(new Stimulus.Fixation({
            duration: 500,
            eyeTrackingRegion: { radius: 50 } // Define AOI
          }))

          // Present attention cue
          .addStimulus(new Stimulus.Arrow({
            direction: 'left',  // Cue attention left
            timing: { onset: 500, duration: 200 },
            position: { x: 0, y: 0 }
          }))
          .addTrigger(new Trigger.EEG({ code: 201, timing: 'stimulus_onset' }))

          // Present target array
          .addStimulus(new Stimulus.FlankersArray({
            target: 'left_arrow',
            flankers: 'incongruent', // ><><><
            position: { x: -300, y: 0 }, // Left side as cued
            timing: { onset: 1000, duration: 150 }
          }))
          .addTrigger(new Trigger.EEG({ code: 301, timing: 'stimulus_onset' }))

          .addResponse(new Response.KeyPress({
            keys: ['left', 'right'],
            correctKey: 'left',
            timeout: 2000
          }))

          // Post-response triggers
          .addTrigger(new Trigger.EEG({ 
            code: 400, 
            timing: 'response',
            condition: 'correct' 
          }))
      )
      .repeat(200) // Many trials for ERP analysis
  )

  .setDataExport({
    format: 'bids',
    includeRawEEG: true,
    includeEyeTracking: true,
    analysisScripts: ['eeglab_preprocessing.m', 'fixation_analysis.py']
  })

  .compile();
