**Authentication Implementation:**
```typescript
// @psyforge/auth
export class AuthenticationManager {
  private keycloakClient: KeycloakClient;
  private tokenManager: TokenManager;

  constructor(config: AuthConfig) {
    this.keycloakClient = new KeycloakClient(config.keycloak);
    this.tokenManager = new TokenManager();
  }

  // Initialize OAuth2 PKCE flow
  async initiateLogin(): Promise<AuthorizationUrl> {
    const codeVerifier = this.generateCodeVerifier();
    const codeChallenge = await this.generateCodeChallenge(codeVerifier);

    // Store PKCE parameters
    this.tokenManager.storePKCEParams(codeVerifier);

    const authUrl = this.keycloakClient.getAuthorizationUrl({
      client_id: 'psyforge-studio',
      redirect_uri: `${window.location.origin}/auth/callback`,
      scope: 'openid profile email',
      response_type: 'code',
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    return authUrl;
  }

  // Handle OAuth callback
  async handleCallback(authorizationCode: string): Promise<AuthenticationResult> {
    const codeVerifier = this.tokenManager.getPKCEVerifier();

    const tokens = await this.keycloakClient.exchangeCodeForTokens({
      code: authorizationCode,
      code_verifier: codeVerifier,
      client_id: 'psyforge-studio',
      redirect_uri: `${window.location.origin}/auth/callback`
    });

    // Validate and store tokens
    const userInfo = await this.validateTokens(tokens);
    this.tokenManager.storeTokens(tokens);

    return {
      user: userInfo,
      permissions: this.extractPermissions(tokens.access_token),
      expiresAt: tokens.expires_at
    };
  }

  // Automatic token refresh
  async refreshTokensIfNeeded(): Promise<boolean> {
    if (!this.tokenManager.needsRefresh()) {
      return false;
    }

    try {
      const refreshToken = this.tokenManager.getRefreshToken();
      const newTokens = await this.keycloakClient.refreshTokens(refreshToken);

      this.tokenManager.storeTokens(newTokens);
      return true;
    } catch (error) {
      // Refresh failed, require re-authentication
      this.tokenManager.clearTokens();
      throw new AuthenticationRequiredError();
    }
  }
}

// Role-based access control
export interface UserPermissions {
  canCreateExperiments: boolean;
  canPublishExperiments: boolean;
  canAccessAnalytics: boolean;
  canManageUsers: boolean;
  maxParticipants: number;
  allowedProviders: string[];
}

export function hasPermission(user: AuthenticatedUser, permission: keyof UserPermissions): boolean {
  return user.permissions[permission] === true;
}
