**Virtual Device Implementation:**
```typescript
// @psyforge/dal-virtual
export class VirtualKeyboard implements InputDevice {
  readonly deviceId = 'virtual-keyboard';
  readonly deviceName = 'Virtual Keyboard';
  readonly deviceType = 'input' as const;
  readonly capabilities = {
    hasNumericKeypad: true,
    hasArrowKeys: true,
    hasFunctionKeys: true
  };

  private eventEmitter = new EventEmitter();
  private isConnected = false;
  private responseModel: KeyboardResponseModel;

  constructor(config: VirtualKeyboardConfig = {}) {
    this.responseModel = new KeyboardResponseModel({
      baseReactionTime: config.baseRT || 350,
      reactionTimeVariability: config.rtVariability || 50,
      errorRate: config.errorRate || 0.02,
      fatigueEffect: config.fatigueEffect || 0.001
    });
  }

  async connect(): Promise<void> {
    this.isConnected = true;
    this.emit('connected');
  }

  async disconnect(): Promise<void> {
    this.isConnected = false;
    this.emit('disconnected');
  }

  // Simulate key press with realistic timing
  simulateKeyPress(key: string, context: ResponseContext = {}): void {
    if (!this.isConnected) return;

    const response = this.responseModel.generateResponse(key, context);

    // Simulate realistic timing delay
    setTimeout(() => {
      this.emit('keypress', {
        key: response.key,
        timestamp: performance.now(),
        reactionTime: response.reactionTime,
        accuracy: response.accuracy,
        deviceId: this.deviceId
      });
    }, response.reactionTime);
  }

  // Auto-response based on stimulus
  autoRespond(stimulus: Stimulus, correctResponse: string): void {
    // Determine if response will be correct based on model
    const shouldRespond = this.responseModel.shouldRespond(stimulus);
    const isCorrect = this.responseModel.isResponseCorrect(stimulus, correctResponse);

    if (shouldRespond) {
      const responseKey = isCorrect ? correctResponse : this.responseModel.generateErrorResponse(correctResponse);
      this.simulateKeyPress(responseKey, {
        stimulus,
        correctResponse,
        trialNumber: stimulus.metadata?.trialNumber
      });
    }
  }

  // Event handling
  on<T extends DeviceEvent>(event: string, listener: (data: T) => void): this {
    this.eventEmitter.on(event, listener);
    return this;
  }

  off(event: string, listener: Function): this {
    this.eventEmitter.off(event, listener);
    return this;
  }

  emit(event: string, data: any): void {
    this.eventEmitter.emit(event, data);
  }
}

// Realistic response modeling
class KeyboardResponseModel {
  constructor(private config: ResponseModelConfig) {}

  generateResponse(key: string, context: ResponseContext): SimulatedResponse {
    const baseRT = this.config.baseReactionTime;
    const variability = this.config.reactionTimeVariability;
    const fatigue = this.calculateFatigue(context.trialNumber || 0);
    const practice = this.calculatePracticeEffect(context.trialNumber || 0);

    // Generate reaction time from ex-Gaussian distribution
    const reactionTime = this.generateExGaussianRT(baseRT, variability) + fatigue - practice;

    // Determine accuracy
    const errorProbability = this.config.errorRate + fatigue * 0.1;
    const accuracy = Math.random() > errorProbability;

    return {
      key: accuracy ? key : this.generateErrorKey(key),
      reactionTime: Math.max(reactionTime, 100), // Minimum 100ms RT
      accuracy
    };
  }

  private generateExGaussianRT(mu: number, sigma: number, tau: number = 50): number {
    // Ex-Gaussian distribution: normal + exponential
    const normal = this.randomNormal(mu, sigma);
    const exponential = -tau * Math.log(Math.random());
    return normal + exponential;
  }

  private randomNormal(mean: number, stdDev: number): number {
    // Box-Muller transform
    const u1 = Math.random();
    const u2 = Math.random();
    const z0 = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
    return z0 * stdDev + mean;
  }
}
```

