**Data Export Implementation:**
```typescript
// @psyforge/export
export class AnalysisReadyExporter {
  private experiment: CompiledExperiment;
  private rawData: ExperimentData[];
  private metadata: ExperimentMetadata;

  constructor(experiment: CompiledExperiment, data: ExperimentData[], metadata: ExperimentMetadata) {
    this.experiment = experiment;
    this.rawData = data;
    this.metadata = metadata;
  }

  // Export to tidy CSV format
  async exportCSV(options: CSVExportOptions = {}): Promise<CSVExportResult> {
    const tidyData = this.transformToTidyFormat(this.rawData);
    const validated = this.validateData(tidyData);

    const csv = this.generateCSV(validated, {
      includeHeaders: options.includeHeaders ?? true,
      delimiter: options.delimiter ?? ',',
      encoding: options.encoding ?? 'utf-8'
    });

    const metadata = this.generateDataDictionary(validated);

    return {
      data: csv,
      metadata: metadata,
      fileName: this.generateFileName('csv'),
      schema: this.generateJSONSchema(validated)
    };
  }

  // Export to Parquet for performance
  async exportParquet(): Promise<ParquetExportResult> {
    const tidyData = this.transformToTidyFormat(this.rawData);
    const validated = this.validateData(tidyData);

    // Convert to Arrow Table for Parquet serialization
    const table = this.convertToArrowTable(validated);
    const parquetBuffer = await this.serializeToParquet(table);

    return {
      data: parquetBuffer,
      fileName: this.generateFileName('parquet'),
      schema: table.schema,
      compressionRatio: this.calculateCompressionRatio(validated, parquetBuffer)
    };
  }

  // Transform raw experiment data to tidy format
  private transformToTidyFormat(rawData: ExperimentData[]): TidyDataRow[] {
    return rawData.map((trial, index) => ({
      // Participant information
      participant_id: trial.participantId,
      session_id: trial.sessionId,
      age: trial.demographics?.age,
      gender: trial.demographics?.gender,

      // Trial identifiers
      trial_number: index + 1,
      trial_id: trial.trialId,
      trial_type: trial.trialType,
      block_id: trial.blockId,
      timeline_id: trial.timelineId,

      // Experimental conditions
      condition: trial.condition,
      condition_level_1: trial.conditionLevels?.[0],
      condition_level_2: trial.conditionLevels?.[1], 
      condition_level_3: trial.conditionLevels?.[2],

      // Stimulus information
      stimulus_id: trial.stimulusId,
      stimulus_type: trial.stimulusType,
      stimulus_content: trial.stimulusContent,
      stimulus_file: trial.stimulusFile,
      stimulus_onset_time: trial.stimulusOnsetTime,
      stimulus_offset_time: trial.stimulusOffsetTime,
      stimulus_duration: trial.stimulusDuration,

      // Response data
      response_key: trial.responseKey,
      response_time: trial.responseTime,
      response_accuracy: trial.responseAccuracy ? 1 : 0,
      response_timeout: trial.responseTimeout ? 1 : 0,
      reaction_time: trial.reactionTime,

      // Timing validation
      stimulus_onset_jitter: trial.timingValidation?.onsetJitter,
      frame_drops: trial.timingValidation?.frameDrops,
      refresh_rate: trial.timingValidation?.refreshRate,

      // Device information
      input_device: trial.inputDevice,
      device_latency: trial.deviceLatency,

      // Experiment metadata
      experiment_name: this.experiment.name,
      experiment_version: this.experiment.version,
      forgescript_version: this.metadata.forgescriptVersion,

      // Timestamps
      trial_start_time: trial.trialStartTime,
      trial_end_time: trial.trialEndTime,
      experiment_start_time: this.metadata.experimentStartTime,

      // Custom variables (flattened)
      ...this.flattenCustomVariables(trial.customVariables)
    }));
  }

  // Generate data dictionary for documentation
  private generateDataDictionary(data: TidyDataRow[]): DataDictionary {
    return {
      participant_id: {
        description: 'Unique identifier for participant',
        type: 'string',
        example: 'P001'
      },
      trial_number: {
        description: 'Sequential trial number within experiment',
        type: 'integer',
        range: [1, data.length]
      },
      condition: {
        description: 'Experimental condition or factor level',
        type: 'categorical',
        levels: [...new Set(data.map(d => d.condition))]
      },
      reaction_time: {
        description: 'Response time in milliseconds from stimulus onset',
        type: 'numeric',
        unit: 'milliseconds',
        missing_value_code: -999
      },
      response_accuracy: {
        description: 'Response accuracy (1 = correct, 0 = incorrect)',
        type: 'binary',
        coding: { 0: 'incorrect', 1: 'correct' }
      },
      stimulus_onset_jitter: {
        description: 'Measured timing precision for stimulus onset',
        type: 'numeric',
        unit: 'milliseconds',
        note: 'Lower values indicate better timing precision'
      }
      // ... additional column descriptions
    };
  }
}

// BIDS-compatible directory structure
export class BIDSExporter extends AnalysisReadyExporter {
  async exportBIDS(): Promise<BIDSExportResult> {
    const structure = await this.generateBIDSStructure();

    return {
      structure: structure,
