        'dataset_description.json': await this.generateDatasetDescription(),
        'task-experiment_events.tsv': await this.exportCSV({ delimiter: '\t' }),
        'task-experiment_bold.json': await this.generateTaskDescription(),
        'README': await this.generateBIDSReadme(),
        'CHANGES': await this.generateChangelog()
      },
      validator_passed: await this.validateBIDSCompliance(structure)
    };
  }

  private async generateBIDSStructure(): Promise<BIDSStructure> {
