```typescript
// @psyforge/analysis-generator
export class AnalysisScriptGenerator {
  private experiment: CompiledExperiment;
  private dataSchema: DataSchema;
  private designType: ExperimentalDesign;

  constructor(experiment: CompiledExperiment, dataSchema: DataSchema) {
    this.experiment = experiment;
    this.dataSchema = dataSchema;
    this.designType = this.detectExperimentalDesign(experiment);
  }

  // Generate R analysis script
  generateRScript(): string {
    const script = new RScriptBuilder()
      .addHeader(this.generateRHeader())
      .addDataLoading(this.generateRDataLoading())
      .addDataPreprocessing(this.generateRPreprocessing())
      .addDescriptiveAnalysis(this.generateRDescriptives())
      .addInferentialAnalysis(this.generateRInferentials())
      .addVisualization(this.generateRPlots())
      .addPowerAnalysis(this.generateRPowerAnalysis())
      .build();

    return script;
  }

  private generateRHeader(): string {
    return `
# ${this.experiment.name} - Analysis Script
# Generated by Psycho-Forge on ${new Date().toISOString()}
# 
# This script performs standard analyses for the experimental design:
# Design Type: ${this.designType.type}
# Factors: ${this.designType.factors.join(', ')}
# Dependent Variables: ${this.designType.dependentVariables.join(', ')}

# Load required packages
library(tidyverse)    # Data manipulation and visualization
library(afex)         # ANOVA functions  
library(emmeans)      # Post-hoc comparisons
library(effectsize)   # Effect size calculations
library(performance) # Model diagnostics
library(report)       # Automated reporting
library(pwr)          # Power analysis

# Set options
options(contrasts = c("contr.sum", "contr.poly"))  # Type III SS
theme_set(theme_minimal())  # Clean ggplot theme
`;
  }

  private generateRDataLoading(): string {
    return `
# Load and prepare data
data_file <- "${this.generateFileName('csv')}"
raw_data <- read_csv(data_file, col_types = cols(
  participant_id = col_character(),
  trial_number = col_integer(),
  condition = col_factor(),
  response_accuracy = col_logical(),
  reaction_time = col_double(),
  .default = col_guess()
))

# Data validation
cat("Data loaded successfully\\n")
cat("Participants:", n_distinct(raw_data$participant_id), "\\n")
cat("Total trials:", nrow(raw_data), "\\n")
cat("Conditions:", paste(levels(raw_data$condition), collapse = ", "), "\\n")
`;
  }

  private generateRPreprocessing(): string {
    return `
# Data preprocessing
clean_data <- raw_data %>%
  # Remove practice trials if present
  filter(!str_detect(timeline_id, "practice")) %>%

  # Remove trials with missing responses
  filter(!is.na(reaction_time), !is.na(response_accuracy)) %>%

  # Remove unrealistic RTs (< 100ms or > 3000ms)
  filter(reaction_time >= 100, reaction_time <= 3000) %>%

  # Remove trials with timing errors > 5ms
  filter(abs(stimulus_onset_jitter) <= 5) %>%

  # Calculate participant-level exclusions
  group_by(participant_id) %>%
  mutate(
    participant_accuracy = mean(response_accuracy, na.rm = TRUE),
    participant_mean_rt = mean(reaction_time[response_accuracy], na.rm = TRUE)
  ) %>%
  ungroup() %>%

  # Exclude participants with < 60% accuracy
  filter(participant_accuracy >= 0.60) %>%

  # Remove outlier RTs (2.5 SD from participant mean)
  group_by(participant_id, condition) %>%
  mutate(
    rt_z = abs(scale(reaction_time)[,1])
  ) %>%
  filter(rt_z <= 2.5) %>%
  ungroup()

cat("After preprocessing:\\n")
cat("Participants remaining:", n_distinct(clean_data$participant_id), "\\n")
cat("Trials remaining:", nrow(clean_data), "\\n")
cat("Data exclusion rate:", 
    round((1 - nrow(clean_data) / nrow(raw_data)) * 100, 1), "%\\n")
`;
  }

  private generateRInferentials(): string {
    if (this.designType.type === 'within_subjects') {
      return this.generateWithinSubjectsANOVA();
    } else if (this.designType.type === 'between_subjects') {
      return this.generateBetweenSubjectsANOVA();
    } else {
      return this.generateMixedDesignANOVA();
    }
  }

  private generateWithinSubjectsANOVA(): string {
    return `
# Within-subjects ANOVA
rt_model <- aov_ez(
  id = "participant_id",
  dv = "reaction_time", 
  data = filter(clean_data, response_accuracy == TRUE),
  within = c(${this.designType.factors.map(f => `"${f}"`).join(', ')})
)

# Model summary
print(rt_model)
print(report(rt_model))

# Effect sizes
print(eta_squared(rt_model, partial = TRUE))

# Post-hoc comparisons
rt_emmeans <- emmeans(rt_model, ~ ${this.designType.factors[0]})
print(contrast(rt_emmeans, "pairwise", adjust = "bonferroni"))

# Accuracy analysis
acc_data <- clean_data %>%
  group_by(participant_id, ${this.designType.factors.join(', ')}) %>%
  summarise(accuracy = mean(response_accuracy), .groups = "drop")

acc_model <- aov_ez(
  id = "participant_id",
  dv = "accuracy",
  data = acc_data,
  within = c(${this.designType.factors.map(f => `"${f}"`).join(', ')})
)

print(acc_model)
print(report(acc_model))
`;
  }
}

// Python script generation
export class PythonAnalysisGenerator {
  generatePythonScript(): string {
    return `
# ${this.experiment.name} - Python Analysis Script
# Generated by Psycho-Forge on ${new Date().toISOString()}

import pandas as pd
import numpy as np
import scipy.stats as stats
import matplotlib.pyplot as plt
import seaborn as sns
from scipy import stats
import pingouin as pg

# Load data
df = pd.read_csv('${this.generateFileName('csv')}')

# Data preprocessing
df_clean = (df
    .query('timeline_id != "practice"')  # Remove practice
    .dropna(subset=['reaction_time', 'response_accuracy'])  # Remove missing
    .query('100 <= reaction_time <= 3000')  # Remove outlier RTs
    .query('abs(stimulus_onset_jitter) <= 5')  # Remove timing errors
)

# Participant-level filtering
participant_accuracy = df_clean.groupby('participant_id')['response_accuracy'].mean()
valid_participants = participant_accuracy[participant_accuracy >= 0.60].index
df_clean = df_clean[df_clean['participant_id'].isin(valid_participants)]

print(f"Data loaded: {len(df)} trials, {df['participant_id'].nunique()} participants")
print(f"After cleaning: {len(df_clean)} trials, {df_clean['participant_id'].nunique()} participants")

# Descriptive statistics
print("\\nDescriptive Statistics:")
desc_stats = df_clean.groupby('condition').agg({
    'reaction_time': ['mean', 'std', 'count'],
    'response_accuracy': 'mean'
}).round(3)
print(desc_stats)

# Inferential statistics
if len(df_clean['condition'].unique()) == 2:
    # Paired t-test for two conditions
    rt_correct = df_clean[df_clean['response_accuracy'] == True]

    condition_1 = rt_correct[rt_correct['condition'] == df_clean['condition'].unique()[0]]['reaction_time']
    condition_2 = rt_correct[rt_correct['condition'] == df_clean['condition'].unique()[1]]['reaction_time']

    t_stat, p_val = stats.ttest_rel(condition_1, condition_2)
    effect_size = (condition_1.mean() - condition_2.mean()) / np.sqrt((condition_1.var() + condition_2.var()) / 2)

    print(f"\\nPaired t-test: t = {t_stat:.3f}, p = {p_val:.3f}")
    print(f"Cohen's d = {effect_size:.3f}")

else:
    # Repeated measures ANOVA for multiple conditions
    rm_anova = pg.rm_anova(data=df_clean[df_clean['response_accuracy'] == True], 
                          dv='reaction_time', within='condition', subject='participant_id')
    print("\\nRepeated Measures ANOVA:")
    print(rm_anova)

# Visualization
plt.figure(figsize=(12, 5))

plt.subplot(1, 2, 1)
sns.boxplot(data=df_clean[df_clean['response_accuracy'] == True], 
           x='condition', y='reaction_time')
plt.title('Reaction Time by Condition')
plt.ylabel('Reaction Time (ms)')

plt.subplot(1, 2, 2)
acc_by_condition = df_clean.groupby(['participant_id', 'condition'])['response_accuracy'].mean().reset_index()
sns.barplot(data=acc_by_condition, x='condition', y='response_accuracy', ci=95)
plt.title('Accuracy by Condition')
plt.ylabel('Accuracy')
plt.ylim(0, 1)

plt.tight_layout()
plt.savefig('analysis_results.png', dpi=300, bbox_inches='tight')
plt.show()
`;
  }
}
