**Methods Generation Implementation:**
```typescript
// @psyforge/methods-generator
export class MethodsGenerator {
  private experiment: CompiledExperiment;
  private template: MethodsTemplate;
  private citations: CitationManager;

  constructor(experiment: CompiledExperiment, template: MethodsTemplate = 'apa') {
    this.experiment = experiment;
    this.template = MethodsTemplates[template];
    this.citations = new CitationManager();
  }

  generateMethodsSection(): MethodsSection {
    return {
      participants: this.generateParticipantsSection(),
      apparatus: this.generateApparatusSection(), 
      stimuli: this.generateStimuliSection(),
      procedure: this.generateProcedureSection(),
      design: this.generateDesignSection(),
      dataAnalysis: this.generateDataAnalysisSection(),
      citations: this.citations.getReferences()
    };
  }

  private generateParticipantsSection(): string {
    const recruitment = this.experiment.recruitment;

    return this.template.format('participants', {
      sampleSize: recruitment?.target?.n || '[N to be determined]',
      ageRange: recruitment?.criteria?.age ? 
        `${recruitment.criteria.age.min}-${recruitment.criteria.age.max} years` : 
        '[age range to be specified]',
      exclusionCriteria: this.formatExclusionCriteria(recruitment?.criteria),
      compensation: recruitment?.compensation ? 
        `$${recruitment.compensation.base} ${recruitment.compensation.currency}` : 
        '[compensation to be specified]',
      recruitmentMethod: this.formatRecruitmentMethod(recruitment?.providers),
      ethicsApproval: '[IRB approval number to be added]'
    });
  }

  private generateApparatusSection(): string {
    const devices = this.experiment.devices || [];
    const timing = this.experiment.timingRequirements;

    return this.template.format('apparatus', {
      computer: 'Standard laboratory computer with [specifications to be added]',
      monitor: `${timing?.targetRefreshRate || 60}Hz LCD monitor`,
      software: `Psycho-Forge ${this.experiment.forgescriptVersion} ${this.citations.cite('psycho-forge')}`,
      inputDevices: devices.length > 0 ? 
        devices.map(d => d.description).join(', ') : 
        'Standard computer keyboard',
      timingPrecision: timing?.guaranteedPrecision ? 
        `Stimulus timing precision verified to ${timing.guaranteedPrecision}ms` : 
        'High-precision stimulus timing validated',
      additionalEquipment: this.formatAdditionalEquipment(devices)
    });
  }

  private generateStimuliSection(): string {
    const stimuli = this.extractStimuliFromExperiment();

    const stimuliDescription = stimuli.map(stimulus => {
      switch (stimulus.type) {
        case 'text':
          return `Text stimuli were presented in ${stimulus.fontSize}pt ${stimulus.fontFamily} font, colored ${stimulus.color}`;
        case 'image':
          return `Image stimuli (${stimulus.format}) were ${stimulus.dimensions} pixels`;
        case 'audio':
          return `Audio stimuli were ${stimulus.sampleRate}Hz ${stimulus.format} files`;
        default:
          return `${stimulus.type} stimuli were presented`;
      }
    }).join('. ');

    return this.template.format('stimuli', {
      description: stimuliDescription,
      timing: this.describeStimulusTiming(),
      positioning: this.describeStimulusPositioning(),
      counterbalancing: this.describeCounterbalancing()
    });
  }

  private generateProcedureSection(): string {
    const timelines = this.experiment.timelines;

    const procedureSteps = timelines.map(timeline => {
      const trialCount = timeline.trials?.length || 0;
      const description = timeline.description || `${timeline.id} phase`;

      return `${description} consisted of ${trialCount} trials`;
    }).join('. ');

    return this.template.format('procedure', {
      overview: procedureSteps,
      trialStructure: this.describeTrialStructure(),
      timing: this.describeOverallTiming(),
      instructions: this.formatInstructions(),
      breaks: this.describeBreaks()
    });
  }

  private generateDataAnalysisSection(): string {
    const design = this.experiment.designType;
    const dvs = this.experiment.dependentVariables;

    return this.template.format('dataAnalysis', {
      exclusionCriteria: this.formatDataExclusionCriteria(),
      dependentVariables: dvs.join(', '),
      statisticalTest: this.recommendStatisticalTest(design),
      alphaLevel: '0.05',
      corrections: 'Bonferroni correction for multiple comparisons',
      software: `R version ${this.citations.cite('r-core')} with packages afex ${this.citations.cite('afex')} and emmeans ${this.citations.cite('emmeans')}`
    });
  }
}

