  private monitorUserInteractionLatency(): void {
    // Monitor key user interactions
    const interactions = ['click', 'keydown', 'drag', 'scroll'];

    interactions.forEach(eventType => {
      document.addEventListener(eventType, (event) => {
        const startTime = performance.now();

        // Measure time to next frame
        requestAnimationFrame(() => {
          const latency = performance.now() - startTime;

          this.metrics.recordInteractionLatency(eventType, latency);

          if (latency > 100) { // More than 100ms is noticeable
            this.alerts.trigger({
              type: 'high_interaction_latency',
              severity: 'medium',
              message: `${eventType} interaction took ${latency.toFixed(1)}ms`,
              data: { eventType, latency, timestamp: startTime }
            });
          }
        });
      });
    });
  }

  // Performance optimization suggestions
  private generateOptimizationSuggestions(): OptimizationSuggestion[] {
    const suggestions: OptimizationSuggestion[] = [];
    const currentMetrics = this.metrics.getCurrentSnapshot();

    // Memory optimizations
    if (currentMetrics.memory.used > this.getMemoryBudget() * 0.8) {
      suggestions.push({
        type: 'memory',
        priority: 'high',
        title: 'Reduce memory usage',
        description: 'Consider reducing the number of stimuli preloaded or experiment complexity',
        actions: [
          'Enable lazy loading for large stimulus sets',
          'Reduce image resolution for non-critical stimuli',
          'Clear unused trial data from memory'
        ]
      });
    }

    // Frame rate optimizations
    if (currentMetrics.frameRate < 60) {
      suggestions.push({
        type: 'performance',
        priority: 'high',
        title: 'Improve frame rate',
        description: 'Optimize rendering performance for smooth stimulus presentation',
        actions: [
          'Reduce number of simultaneous animations',
          'Enable hardware acceleration',
          'Simplify visual effects'
        ]
      });
    }

    // Network optimizations
    if (currentMetrics.networkLatency > 200) {
      suggestions.push({
        type: 'network',
        priority: 'medium',
        title: 'Improve collaboration performance',
        description: 'Reduce network latency for better real-time collaboration',
        actions: [
          'Check internet connection quality',
          'Consider using local network for collaboration',
          'Reduce frequency of sync updates'
        ]
      });
    }

    return suggestions;
  }
}

// Performance dashboard UI
export function PerformanceDashboard() {
  const [metrics, setMetrics] = useState<PerformanceSnapshot>();
  const [suggestions, setSuggestions] = useState<OptimizationSuggestion[]>([]);

  useEffect(() => {
    const rapd = new RAPDMonitor();

    // Update metrics every second
    const interval = setInterval(() => {
      setMetrics(rapd.getCurrentMetrics());
      setSuggestions(rapd.getOptimizationSuggestions());
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="performance-dashboard">
      <div className="metrics-grid">
        <MetricCard
          title="Memory Usage"
          value={metrics?.memory.used ? `${(metrics.memory.used / 1024 / 1024).toFixed(1)} MB` : 'N/A'}
          target="< 100 MB"
          status={metrics?.memory.used ? (metrics.memory.used / 1024 / 1024 < 100 ? 'good' : 'warning') : 'unknown'}
        />

        <MetricCard
          title="Frame Rate"
          value={metrics?.frameRate ? `${metrics.frameRate} FPS` : 'N/A'}
          target="60 FPS"
          status={metrics?.frameRate ? (metrics.frameRate >= 60 ? 'good' : 'warning') : 'unknown'}
        />

        <MetricCard
          title="Network Latency"
          value={metrics?.networkLatency ? `${metrics.networkLatency} ms` : 'N/A'}
          target="< 100 ms"
          status={metrics?.networkLatency ? (metrics.networkLatency < 100 ? 'good' : 'warning') : 'unknown'}
        />

        <MetricCard
          title="Sync Performance"
          value={metrics?.crdtSyncLatency ? `${metrics.crdtSyncLatency} ms` : 'N/A'}
          target="< 50 ms"
          status={metrics?.crdtSyncLatency ? (metrics.crdtSyncLatency < 50 ? 'good' : 'warning') : 'unknown'}
        />
      </div>

      {suggestions.length > 0 && (
        <div className="optimization-suggestions">
          <h3>Performance Recommendations</h3>
          {suggestions.map((suggestion, index) => (
            <SuggestionCard key={index} suggestion={suggestion} />
          ))}
        </div>
      )}

      <div className="performance-charts">
        <MemoryUsageChart data={metrics?.memoryHistory} />
        <FrameRateChart data={metrics?.frameRateHistory} />
        <NetworkLatencyChart data={metrics?.networkHistory} />
      </div>
    </div>
  );
}
